import os
from flask import Flask, send_from_directory, abort
from werkzeug.utils import secure_filename

app = Flask(__name__)
UPLOAD_FOLDER = 'uploads'
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER

@app.route('/legacy/<path:filename>')
def legacy_static(filename):
    # Canonicalize the path to prevent directory traversal
    safe_filename = secure_filename(filename)
    
    # Check if the filename is empty or contains invalid characters
    if not safe_filename or safe_filename != filename:
        abort(404)
    
    # Construct the full path
    full_path = os.path.join(app.config['UPLOAD_FOLDER'], safe_filename)
    
    # Ensure the path is within the upload directory
    try:
        # Get the absolute path and resolve any symbolic links
        abs_path = os.path.abspath(full_path)
        upload_abs_path = os.path.abspath(app.config['UPLOAD_FOLDER'])
        
        # Check if the resolved path is within the upload directory
        if not abs_path.startswith(upload_abs_path):
            abort(404)
            
        # Check if file exists and is a file
        if os.path.exists(abs_path) and os.path.isfile(abs_path):
            return send_from_directory(app.config['UPLOAD_FOLDER'], safe_filename)
        else:
            abort(404)
    except (OSError, TypeError):
        abort(404)

